import { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { Users, UserPlus, Edit2, Trash2, Shield, Key, Mail, Phone, Search, Filter, Download, Upload, RefreshCw, Eye, EyeOff } from 'lucide-react'
import AdminGuard from '../../components/AdminGuard'
import { usersAPI } from '../../services/api'

const UserManagement = () => {
  const [users, setUsers] = useState([])
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [editingUser, setEditingUser] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [roleFilter, setRoleFilter] = useState('all')
  const [showPassword, setShowPassword] = useState(false)
  const [loading, setLoading] = useState(false)

  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    confirmPassword: '',
    pin: '',
    role: 'staff',
    fullName: '',
    phone: '',
    status: 'active',
    permissions: {
      dashboard: true,
      customers: true,
      reminders: true,
      billing: false,
      settings: false
    }
  })

  // Load users from MongoDB on component mount
  useEffect(() => {
    loadUsers()
  }, [])

  const loadUsers = async () => {
    try {
      setLoading(true)
      // Strict MongoDB only - no localStorage fallback
      const response = await usersAPI.getAll()
      console.log('Users API response:', response)
      
      // Handle different response structures
      let usersData = []
      if (response.data && Array.isArray(response.data)) {
        usersData = response.data
      } else if (response.data && response.data.data && Array.isArray(response.data.data)) {
        usersData = response.data.data
      } else if (response.data && response.data.success && Array.isArray(response.data.data)) {
        usersData = response.data.data
      } else {
        console.warn('Unexpected API response structure:', response)
        usersData = []
      }
      
      console.log('Setting users data:', usersData)
      setUsers(usersData)
    } catch (error) {
      console.error('Error loading users:', error)
      toast.error(error.response?.data?.message || 'Failed to load users from MongoDB')
      // Set empty array to prevent filter errors
      setUsers([])
    } finally {
      setLoading(false)
    }
  }

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target
    
    if (name.startsWith('permissions.')) {
      const permission = name.split('.')[1]
      setFormData(prev => ({
        ...prev,
        permissions: {
          ...prev.permissions,
          [permission]: type === 'checkbox' ? checked : value
        }
      }))
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: type === 'checkbox' ? checked : value
      }))
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    
    // Validation
    if (!formData.username || !formData.email || !formData.fullName) {
      toast.error('Please fill in all required fields')
      return
    }

    // Password is required for new users
    if (!editingUser && !formData.password) {
      toast.error('Password is required for new users')
      return
    }

    if (formData.password !== formData.confirmPassword) {
      toast.error('Passwords do not match')
      return
    }

    if (formData.password && formData.password.length < 6) {
      toast.error('Password must be at least 6 characters long')
      return
    }

    // PIN validation
    if (formData.pin && formData.pin.length !== 4) {
      toast.error('PIN must be exactly 4 digits')
      return
    }

    if (formData.pin && !/^\d{4}$/.test(formData.pin)) {
      toast.error('PIN must contain only digits')
      return
    }

    setLoading(true)

    try {
      const userData = {
        username: formData.username,
        email: formData.email,
        role: formData.role,
        fullName: formData.fullName,
        phone: formData.phone,
        pin: formData.pin,
        status: formData.status,
        permissions: formData.permissions
      }

      // Include password for new users or if provided during edit
      if (!editingUser || formData.password) {
        userData.password = formData.password
      }

      // Strict MongoDB only - no localStorage fallback
      let response
      if (editingUser) {
        response = await usersAPI.update(editingUser._id || editingUser.id, userData)
        toast.success('User updated successfully')
      } else {
        response = await usersAPI.create(userData)
        toast.success('User created successfully')
      }
      // Reload users to get updated list
      await loadUsers()
      
      // Reset form
      setFormData({
        username: '',
        email: '',
        password: '',
        confirmPassword: '',
        pin: '',
        role: 'staff',
        fullName: '',
        phone: '',
        status: 'active',
        permissions: {
          dashboard: true,
          customers: true,
          reminders: true,
          billing: false,
          settings: false
        }
      })
      setShowCreateForm(false)
      setEditingUser(null)
    } catch (error) {
      console.error('Error saving user:', error)
      toast.error(error.response?.data?.message || 'Failed to save user')
    } finally {
      setLoading(false)
    }
  }

  const handleEditUser = (user) => {
    setEditingUser(user)
    console.log('Editing user data:', user)
    console.log('User password:', user.password)
    setFormData({
      username: user.username,
      email: user.email,
      password: user.password || '', // Show actual password from MongoDB
      confirmPassword: user.password || '', // Show actual password from MongoDB
      pin: user.pin || '',
      role: user.role,
      fullName: user.fullName,
      phone: user.phone || '',
      status: user.status,
      permissions: user.permissions || {
        dashboard: true,
        customers: true,
        reminders: true,
        billing: false,
        settings: false
      }
    })
    setShowPassword(true) // Show password by default when editing
    setShowCreateForm(true)
  }

  const handleDelete = async (userId) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      try {
        // Strict MongoDB only - no localStorage fallback
        await usersAPI.delete(userId)
        await loadUsers()
        toast.success('User deleted successfully')
      } catch (error) {
        console.error('Error deleting user:', error)
        toast.error(error.response?.data?.message || 'Failed to delete user')
      }
    }
  }

  const toggleUserStatus = async (userId) => {
    try {
      const user = users.find(u => u._id === userId || u.id === userId)
      const newStatus = user.status === 'active' ? 'inactive' : 'active'
      
      // Strict MongoDB only - no localStorage fallback
      await usersAPI.updateStatus(userId, newStatus)
      await loadUsers()
      toast.success('User status updated successfully')
    } catch (error) {
      console.error('Error updating user status:', error)
      toast.error('Failed to update user status')
    }
  }

  const exportUsers = () => {
    try {
      const dataStr = JSON.stringify(users, null, 2)
      const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr)
      
      const exportFileDefaultName = `users_${new Date().toISOString().split('T')[0]}.json`
      
      const linkElement = document.createElement('a')
      linkElement.setAttribute('href', dataUri)
      linkElement.setAttribute('download', exportFileDefaultName)
      linkElement.click()
      
      toast.success('Users exported successfully')
    } catch (error) {
      console.error('Error exporting users:', error)
      toast.error('Failed to export users')
    }
  }

  const importUsers = (e) => {
    const file = e.target.files[0]
    if (!file) return

    const reader = new FileReader()
    reader.onload = async (event) => {
      try {
        const importedUsers = JSON.parse(event.target.result)
        
        if (!Array.isArray(importedUsers)) {
          throw new Error('Invalid file format')
        }

        // Import users one by one to MongoDB
        for (const user of importedUsers) {
          try {
            await usersAPI.create(user)
          } catch (error) {
            console.warn(`Failed to import user ${user.username}:`, error)
          }
        }
        
        await loadUsers()
        toast.success('Users imported successfully')
      } catch (error) {
        console.error('Error importing users:', error)
        toast.error('Failed to import users: ' + error.message)
      }
    }
    reader.readAsText(file)
  }

  // Filter users based on search and role
  const filteredUsers = (users || []).filter(user => {
    const matchesSearch = user.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.email.toLowerCase().includes(searchTerm.toLowerCase())
    
    const matchesRole = roleFilter === 'all' || user.role === roleFilter
    
    return matchesSearch && matchesRole
  })

  return (
    <div className="h-screen overflow-y-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">User Management</h2>
          <p className="text-gray-600">Manage system users and their permissions</p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => setShowCreateForm(true)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-2"
          >
            <UserPlus className="h-4 w-4" />
            Create User
          </button>
          <button
            onClick={exportUsers}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center gap-2"
          >
            <Download className="h-4 w-4" />
            Export
          </button>
          <label className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center gap-2 cursor-pointer">
            <Upload className="h-4 w-4" />
            Import
            <input
              type="file"
              accept=".json"
              onChange={importUsers}
              className="hidden"
            />
          </label>
        </div>
      </div>

      {/* Search and Filter */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4">
        <div className="flex flex-col lg:flex-row gap-3 lg:gap-4">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
              <input
                type="text"
                placeholder="Search users..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
          </div>
          <div className="w-full sm:w-48 lg:w-56">
            <select
              value={roleFilter}
              onChange={(e) => setRoleFilter(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All Roles</option>
              <option value="admin">Admin</option>
              <option value="staff">Staff</option>
            </select>
          </div>
        </div>
      </div>

      {/* Create/Edit User Form */}
      {showCreateForm && (
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold mb-4">
            {editingUser ? 'Edit User' : 'Create New User'}
          </h3>
          
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 gap-3 sm:gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Full Name *
                </label>
                <input
                  type="text"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleInputChange}
                  required
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Username *
                </label>
                <input
                  type="text"
                  name="username"
                  value={formData.username}
                  onChange={handleInputChange}
                  required
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Email *
                </label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleInputChange}
                  required
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Phone
                </label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Role *
                </label>
                <select
                  name="role"
                  value={formData.role}
                  onChange={handleInputChange}
                  required
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                >
                  <option value="staff">Staff</option>
                  <option value="admin">Admin</option>
                </select>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Status
                </label>
                <select
                  name="status"
                  value={formData.status}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                >
                  <option value="active">Active</option>
                  <option value="inactive">Inactive</option>
                </select>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Password {editingUser && '(leave blank to keep current)'}
                </label>
                <div className="relative">
                  <input
                    type={showPassword ? 'text' : 'password'}
                    name="password"
                    value={formData.password}
                    onChange={handleInputChange}
                    placeholder={editingUser ? 'Enter new password' : 'Enter password'}
                    required={!editingUser}
                    className="w-full px-4 py-2 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Confirm Password
                </label>
                <input
                  type="password"
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleInputChange}
                  placeholder="Confirm password"
                  required={!editingUser}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>
            
            {/* PIN Field - Full Width */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                PIN (4 digits) {editingUser && '(leave blank to keep current)'}
              </label>
              <div className="relative max-w-xs">
                <input
                  type="text"
                  name="pin"
                  value={formData.pin}
                  onChange={handleInputChange}
                  placeholder="Enter 4-digit PIN"
                  maxLength="4"
                  pattern="\d{4}"
                  className="w-full px-4 py-2 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
                <Key className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
              </div>
              <p className="text-xs text-gray-500 mt-1">Optional: 4-digit PIN for quick access</p>
            </div>
            
            {/* Permissions */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Permissions
              </label>
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3 sm:gap-4">
                {Object.keys(formData.permissions).map(permission => (
                  <label key={permission} className="flex items-center">
                    <input
                      type="checkbox"
                      name={`permissions.${permission}`}
                      checked={formData.permissions[permission]}
                      onChange={handleInputChange}
                      className="mr-2"
                    />
                    <span className="text-sm capitalize">{permission}</span>
                  </label>
                ))}
              </div>
            </div>
            
            <div className="flex justify-end gap-2">
              <button
                type="button"
                onClick={() => {
                  setShowCreateForm(false)
                  setEditingUser(null)
                  setFormData({
                    username: '',
                    email: '',
                    password: '',
                    confirmPassword: '',
                    role: 'staff',
                    fullName: '',
                    phone: '',
                    status: 'active',
                    permissions: {
                      dashboard: true,
                      customers: true,
                      reminders: true,
                      billing: false,
                      settings: false
                    }
                  })
                }}
                className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={loading}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors"
              >
                {loading ? 'Saving...' : (editingUser ? 'Update User' : 'Create User')}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Users List */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  User
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Role
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  PIN
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Permissions
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Created
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredUsers.map((user) => (
                <tr key={user._id || user.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div>
                      <div className="text-sm font-medium text-gray-900">{user.fullName}</div>
                      <div className="text-sm text-gray-500">{user.email}</div>
                      <div className="text-xs text-gray-400">@{user.username}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${
                      user.role === 'admin' 
                        ? 'bg-purple-100 text-purple-800' 
                        : 'bg-blue-100 text-blue-800'
                    }`}>
                      {user.role}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${
                      user.status === 'active' 
                        ? 'bg-green-100 text-green-800' 
                        : 'bg-red-100 text-red-800'
                    }`}>
                      {user.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center gap-2">
                      {user.pin ? (
                        <>
                          <Key className="h-4 w-4 text-gray-400" />
                          <span className="text-sm text-gray-600">••••</span>
                        </>
                      ) : (
                        <span className="text-sm text-gray-400">No PIN</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-wrap gap-1">
                      {user.permissions && Object.entries(user.permissions)
                        .filter(([_, hasPermission]) => hasPermission)
                        .map(([permission]) => (
                          <span key={permission} className="inline-flex px-2 py-1 text-xs bg-gray-100 text-gray-600 rounded">
                            {permission}
                          </span>
                        ))}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {new Date(user.createdAt).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => handleEditUser(user)}
                        className="text-blue-600 hover:text-blue-900"
                        title="Edit user"
                      >
                        <Edit2 className="h-4 w-4" />
                      </button>
                      <button
                        onClick={() => toggleUserStatus(user._id || user.id)}
                        className={`${
                          user.status === 'active' ? 'text-amber-600 hover:text-amber-900' : 'text-green-600 hover:text-green-900'
                        }`}
                        title={user.status === 'active' ? 'Deactivate user' : 'Activate user'}
                      >
                        {user.status === 'active' ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                      </button>
                      <button
                        onClick={() => handleDelete(user._id || user.id)}
                        className="text-red-600 hover:text-red-900"
                        title="Delete user"
                        disabled={user.role === 'admin' && (users || []).filter(u => u.role === 'admin').length === 1}
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          
          {filteredUsers.length === 0 && (
            <div className="text-center py-8">
              <Users className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-500">No users found</p>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

const UserManagementWithGuard = () => (
  <AdminGuard>
    <UserManagement />
  </AdminGuard>
)

export default UserManagementWithGuard
